CODE_EXAMPLE:
// Focused on version data only
class Version {
    private int major;
    private int minor;
    int getMajorVersionNumber() { return major; }
    int getMinorVersionNumber() { return minor; }
    String getVersionString()   { return major + "." + minor; }
}

// Separate class owns the persistence concern
class VersionRepository {
    void save(Version v, Connection c) { ... }
}

UNIT_TEST_EXAMPLE:
@Test
public void version_formatsVersionString() {
    Version v = new Version(2, 5);
    assertEquals("2.5", v.getVersionString());
}

@Test
public void versionRepository_savesVersion() {
    VersionRepository repo = new VersionRepository(mockConnection);
    repo.save(new Version(1, 0), mockConnection);
    verify(mockConnection).save(any());
}
